  if (CastOpc == Instruction::PtrToInt) {
    if (auto *GEP = dyn_cast<GEPOperator>(Op)) {
      if (GEP->getNumIndices() == 1 && GEP->hasAllConstantIndices() == false) {
        Value *Offset = GEP->getOperand(1);
        Value *X, *PtrInt;
        // Match: offset = X - ptrtoint(base)
        if (match(Offset, m_Sub(m_Value(X), m_Value(PtrInt)))) {
          if (match(PtrInt, m_PtrToInt(m_Specific(GEP->getPointerOperand())))) {
            if (X->getType() == Ty)
              return X;
          }
        }
      }
    }
  }

  // bitcast x -> x
  if (CastOpc == Instruction::BitCast)
    if (Op->getType() == Ty)
      return Op;

  return nullptr;
}

